#include <stdio.h>
int parent[1000000];
int size[1000000];

void swap(int *x, int *y)
{
    int temp = *x;
    *x = *y;
    *y = temp;
}

int dsuFind(int a){
    if(parent[a]==a) return a;
    //fill in the blanks for the optimized find in DSU
    return parent[a] = dsuFind(parent[a]);
}

void dsuUnion(int a, int b) {
    int leader_a = dsuFind(a);
    int leader_b = dsuFind(b);
    if(leader_a!=leader_b)
    {
        //fill in the blanks for the optimized union in DSU
        if(size[leader_b]<size[leader_a])
        {
            swap(&leader_a, &leader_b);
        }
        parent[leader_b] = leader_a;
        size[leader_a]+=size[leader_b];
    }
}
int main(void) {
    int n, m;
    scanf("%d", &n);
    scanf("%d", &m);
    for(int i=0; i<n; i++)
