class DSU {
    constructor(n) {
        this.parent = new Array(n);
        this.setSize = new Array(n);
        for (let i = 0; i < n; i++) {
            this.parent[i] = i;
            this.setSize[i] = 1;
        }
    }

    dsuFind(a) {
        if (this.parent[a] === a) {
            return a;
        }
        // Path compression optimization
        return this.parent[a] = this.dsuFind(this.parent[a]);
    }

    dsuUnion(a, b) {
        let leader_a = this.dsuFind(a);
        let leader_b = this.dsuFind(b);

        if (leader_a !== leader_b) {
            // Union by size optimization
            if (this.setSize[leader_b] < this.setSize[leader_a]) {
                [leader_a, leader_b] = [leader_b, leader_a];
            }
            this.parent[leader_b] = leader_a;
            this.setSize[leader_a] += this.setSize[leader_b];
        }
    }
}

function main() {
    const readline = require('readline');
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout,
        terminal: false
    });

    let n, m;
    let dsu;

    rl.on('line', function(line) {
        const tokens = line.trim().split(' ');
        if (!n) {
            n = parseInt(tokens[0]);
            m = parseInt(tokens[1]);
            dsu = new DSU(n);
        } else {
            const command = tokens[0];
            if (command === 'union') {
                const a = parseInt(tokens[1]);
                const b = parseInt(tokens[2]);
                dsu.dsuUnion(a, b);
            } else if (command === 'find') {
                const a = parseInt(tokens[1]);
                console.log(dsu.dsuFind(a));
            }
        }
    });
}

main();
